    base_inflation_factor = 1.05
    high_usage_inflation = 1.15

    # Update the count of how many times each edge has been used
    n = edge_distance.shape[0]
    for tour in local_opt_tours:
        for i in range(len(tour)):
            if i == len(tour) - 1:
