                from_node, to_node = tour[i], tour[i+1]
            edge_n_used[from_node, to_node] += 1
            edge_n_used[to_node, from_node] += 1

    # Determine the high usage and very high usage thresholds
    high_usage_threshold = np.percentile(edge_n_used, 70)
    very_high_usage_threshold = np.percentile(edge_n_used, 90)

    # Update distances based on the defined thresholds
    updated_edge_distance = np.copy(edge_distance)
    for i in range(n):
        for j in range(n):
            if edge_n_used[i, j] >= very_high_usage_threshold:
                updated_edge_distance[i, j] *= high_usage_inflation
            elif edge_n_used[i, j] >= high_usage_threshold:
                updated_edge_distance[i, j] *= base_inflation_factor

    return updated_edge_distance
